import React, { useEffect, useRef, useState } from 'react';
import { Box } from '@mui/material';

/* ── Tiny canvas fox that walks around the screen ── */
export default function FoxPet() {
  const canvasRef = useRef(null);
  const stateRef = useRef({
    x: 120, y: window.innerHeight - 80,
    vx: 1.2, vy: 0,
    frame: 0, tick: 0,
    dir: 1, // 1=right, -1=left
    action: 'walk', // walk | sit | wag | run
    actionTimer: 0,
    groundY: window.innerHeight - 60,
    blinkTimer: 0, blink: false,
    tailAngle: 0,
  });
  const [tooltip, setTooltip] = useState('');
  const tooltipTimer = useRef(null);

  const PHRASES = ['🦊', '...', 'hi!', 'zzz', '!', ':3', '♪', '✨'];

  const showTooltip = () => {
    const phrase = PHRASES[Math.floor(Math.random() * PHRASES.length)];
    setTooltip(phrase);
    clearTimeout(tooltipTimer.current);
    tooltipTimer.current = setTimeout(() => setTooltip(''), 1800);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let W = canvas.width = window.innerWidth;
    let H = canvas.height = window.innerHeight;
    let raf;

    const resize = () => {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
      stateRef.current.groundY = H - 60;
    };
    window.addEventListener('resize', resize);

    const s = stateRef.current;

    /* ── Draw fox ── */
    function drawFox(ctx, x, y, dir, frame, action, blink, tailAngle) {
      ctx.save();
      ctx.translate(x, y);
      if (dir === -1) { ctx.scale(-1, 1); }

      const run = action === 'run';
      const sit = action === 'sit';
      const t = frame * 0.18;

      // Body bob
      const bob = sit ? 0 : Math.sin(t * (run ? 2 : 1)) * (run ? 3 : 2);

      // ── TAIL ──
      const tailSwing = sit ? Math.sin(t * 2) * 18 : Math.sin(t) * 12;
      const ta = tailAngle + tailSwing;
      ctx.save();
      ctx.translate(-10, -8 + bob);
      ctx.rotate((ta * Math.PI) / 180);
      // tail base
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.bezierCurveTo(-8, -10, -14, -22, -6, -30);
      ctx.bezierCurveTo(0, -36, 10, -28, 8, -18);
      ctx.bezierCurveTo(6, -8, 2, 0, 0, 0);
      ctx.fillStyle = '#e07b39';
      ctx.fill();
      // tail tip
      ctx.beginPath();
      ctx.ellipse(-4, -30, 7, 6, (-30 * Math.PI) / 180, 0, Math.PI * 2);
      ctx.fillStyle = '#f5f5f0';
      ctx.fill();
      ctx.restore();

      // ── BODY ──
      ctx.save();
      ctx.translate(0, bob);
      ctx.beginPath();
      ctx.ellipse(0, -14, 14, 10, 0, 0, Math.PI * 2);
      ctx.fillStyle = '#e07b39';
      ctx.fill();

      // belly
      ctx.beginPath();
      ctx.ellipse(4, -12, 8, 6, 0.2, 0, Math.PI * 2);
      ctx.fillStyle = '#f5e6d0';
      ctx.fill();

      // ── LEGS ──
      if (!sit) {
        const legSwing = Math.sin(t * (run ? 2 : 1)) * (run ? 14 : 8);
        // back legs
        ctx.beginPath(); ctx.moveTo(-6, -8);
        ctx.lineTo(-6 - legSwing * 0.5, 0);
        ctx.lineWidth = 4; ctx.strokeStyle = '#c0612a'; ctx.lineCap = 'round'; ctx.stroke();
        ctx.beginPath(); ctx.moveTo(-3, -8);
        ctx.lineTo(-3 + legSwing * 0.5, 0);
        ctx.stroke();
        // front legs
        ctx.beginPath(); ctx.moveTo(6, -10);
        ctx.lineTo(6 + legSwing, 0);
        ctx.stroke();
        ctx.beginPath(); ctx.moveTo(9, -10);
        ctx.lineTo(9 - legSwing, 0);
        ctx.stroke();
      } else {
        // sitting legs
        ctx.beginPath(); ctx.moveTo(-5, -8); ctx.lineTo(-8, 0); ctx.lineTo(0, 0);
        ctx.lineWidth = 4; ctx.strokeStyle = '#c0612a'; ctx.lineCap = 'round'; ctx.stroke();
        ctx.beginPath(); ctx.moveTo(5, -8); ctx.lineTo(8, 0); ctx.lineTo(16, 0);
        ctx.stroke();
      }
      ctx.restore();

      // ── HEAD ──
      ctx.save();
      ctx.translate(12, -22 + bob);
      // head
      ctx.beginPath();
      ctx.ellipse(0, 0, 11, 9, 0, 0, Math.PI * 2);
      ctx.fillStyle = '#e07b39';
      ctx.fill();

      // ears
      ctx.beginPath();
      ctx.moveTo(-5, -8);
      ctx.lineTo(-8, -18);
      ctx.lineTo(0, -10);
      ctx.fillStyle = '#e07b39';
      ctx.fill();
      // inner ear
      ctx.beginPath();
      ctx.moveTo(-5, -9);
      ctx.lineTo(-7, -16);
      ctx.lineTo(-1, -10);
      ctx.fillStyle = '#f0a0a0';
      ctx.fill();

      ctx.beginPath();
      ctx.moveTo(5, -8);
      ctx.lineTo(10, -17);
      ctx.lineTo(12, -9);
      ctx.fillStyle = '#e07b39';
      ctx.fill();
      ctx.beginPath();
      ctx.moveTo(6, -9);
      ctx.lineTo(9, -15);
      ctx.lineTo(11, -10);
      ctx.fillStyle = '#f0a0a0';
      ctx.fill();

      // face mask
      ctx.beginPath();
      ctx.ellipse(3, 2, 8, 6, 0, 0, Math.PI * 2);
      ctx.fillStyle = '#f5e6d0';
      ctx.fill();

      // eyes
      if (!blink) {
        ctx.beginPath();
        ctx.arc(-3, -2, 2.5, 0, Math.PI * 2);
        ctx.fillStyle = '#1a0a00';
        ctx.fill();
        // shine
        ctx.beginPath();
        ctx.arc(-2.2, -2.8, 0.8, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.8)';
        ctx.fill();

        ctx.beginPath();
        ctx.arc(4, -2, 2.5, 0, Math.PI * 2);
        ctx.fillStyle = '#1a0a00';
        ctx.fill();
        ctx.beginPath();
        ctx.arc(4.8, -2.8, 0.8, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.8)';
        ctx.fill();
      } else {
        // blink lines
        ctx.beginPath(); ctx.moveTo(-5, -2); ctx.lineTo(-1, -2);
        ctx.lineWidth = 2; ctx.strokeStyle = '#1a0a00'; ctx.stroke();
        ctx.beginPath(); ctx.moveTo(2, -2); ctx.lineTo(6, -2); ctx.stroke();
      }

      // nose
      ctx.beginPath();
      ctx.ellipse(7, 2, 2.5, 1.8, 0, 0, Math.PI * 2);
      ctx.fillStyle = '#8b2500';
      ctx.fill();

      // mouth
      ctx.beginPath();
      ctx.moveTo(5, 4);
      ctx.quadraticCurveTo(7, 7, 9, 4);
      ctx.lineWidth = 1.2;
      ctx.strokeStyle = '#8b2500';
      ctx.stroke();

      ctx.restore();
      ctx.restore();
    }

    /* ── Main loop ── */
    function loop() {
      ctx.clearRect(0, 0, W, H);

      s.tick++;
      s.frame++;
      s.actionTimer--;
      s.blinkTimer--;
      s.tailAngle = Math.sin(s.tick * 0.05) * 10;

      // Blink
      if (s.blinkTimer <= 0) {
        s.blink = !s.blink;
        s.blinkTimer = s.blink ? 6 : (80 + Math.random() * 120);
      }

      // Action transitions
      if (s.actionTimer <= 0) {
        const roll = Math.random();
        if (roll < 0.5) { s.action = 'walk'; s.vx = s.dir * (1.0 + Math.random()); s.actionTimer = 120 + Math.random() * 200; }
        else if (roll < 0.65) { s.action = 'run'; s.vx = s.dir * (2.5 + Math.random()); s.actionTimer = 60 + Math.random() * 80; }
        else if (roll < 0.85) { s.action = 'sit'; s.vx = 0; s.actionTimer = 100 + Math.random() * 150; }
        else { s.action = 'wag'; s.vx = 0; s.actionTimer = 80 + Math.random() * 100; }
      }

      // Move
      s.x += s.vx;
      s.y = s.groundY; // stay on ground

      // Bounce off walls
      const margin = 40;
      if (s.x > W - margin) { s.x = W - margin; s.dir = -1; s.vx = -Math.abs(s.vx); s.action = 'walk'; s.actionTimer = 60; }
      if (s.x < margin) { s.x = margin; s.dir = 1; s.vx = Math.abs(s.vx); s.action = 'walk'; s.actionTimer = 60; }

      // Update dir from velocity
      if (s.vx > 0.1) s.dir = 1;
      if (s.vx < -0.1) s.dir = -1;

      drawFox(ctx, s.x, s.y, s.dir, s.frame, s.action, s.blink, s.tailAngle);
      raf = requestAnimationFrame(loop);
    }

    raf = requestAnimationFrame(loop);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', resize);
    };
  }, []);

  return (
    <>
      <canvas
        ref={canvasRef}
        onClick={showTooltip}
        style={{
          position: 'fixed', bottom: 0, left: 0,
          width: '100%', height: '100%',
          pointerEvents: 'none',
          zIndex: 998,
        }}
      />
      {/* Clickable overlay just on fox position */}
      {tooltip && (
        <Box sx={{
          position: 'fixed',
          bottom: 80,
          left: stateRef.current.x - 20,
          zIndex: 999,
          bgcolor: 'rgba(13,38,24,0.9)',
          border: '1px solid rgba(148,204,171,0.3)',
          borderRadius: 99,
          px: 1.5, py: 0.5,
          fontSize: '0.8rem',
          color: '#e8f5ee',
          fontWeight: 700,
          pointerEvents: 'none',
          animation: 'fadeUp 0.2s ease',
          '@keyframes fadeUp': { from: { opacity: 0, transform: 'translateY(8px)' }, to: { opacity: 1, transform: 'translateY(0)' } },
        }}>
          {tooltip}
        </Box>
      )}
    </>
  );
}
